// Command tyk-gen reads each services/<svc>/openapi.yaml and emits a Tyk
// ApiDefinition CR into infra/gateway/apis/<svc>.yaml (ADR-0009).
//
// The generator is intentionally minimal — it produces the smallest valid
// ApiDefinition with the upstream service URL and rate-limiting placeholders.
// Hand editing of the generated files is forbidden; bump the OpenAPI spec or
// the generator instead.
package main

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"
)

const tmpl = `# GENERATED by tools/codegen/tyk-gen. DO NOT EDIT.
apiVersion: tyk.tyk.io/v1alpha1
kind: ApiDefinition
metadata:
  name: %s
  namespace: tyk
spec:
  name: %s
  active: true
  protocol: http
  use_keyless: false
  openapi_path: /apis/%s/openapi.yaml
  proxy:
    target_url: http://%s-server.platform.svc.cluster.local:8080
    strip_listen_path: true
    listen_path: /api/%s/
  do_not_track: false
`

func main() {
	matches, err := filepath.Glob("services/*/openapi.yaml")
	if err != nil {
		fatal(err)
	}
	err = os.MkdirAll("infra/gateway/apis", 0o755)
	if err != nil {
		fatal(err)
	}

	for _, spec := range matches {
		svc := filepath.Base(filepath.Dir(spec))
		out := filepath.Join("infra/gateway/apis", svc+".yaml")
		body := fmt.Sprintf(tmpl, svc, svc, svc, svc, svc)
		err = os.WriteFile(out, []byte(body), 0o644)
		if err != nil {
			fatal(err)
		}
		fmt.Println("→", out)
	}

	if len(matches) == 0 {
		fmt.Println("(no services with openapi.yaml yet)")
	}
}

func fatal(err error) {
	fmt.Fprintln(os.Stderr, "tyk-gen:", strings.TrimSpace(err.Error()))
	os.Exit(1)
}
